import type { ComponentProps, ComponentRef } from 'react';
import { Tabs as TabsPrimitive, useTabs, useTabsContext } from '@ark-ui/react/tabs';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Tabs.module.css';

type TabsVariant = 'default' | 'line';

type TabsRootProps = ComponentProps<typeof TabsPrimitive.Root> & {
  variant?: TabsVariant;
};

type TabsRootProviderProps = ComponentProps<typeof TabsPrimitive.RootProvider> & {
  variant?: TabsVariant;
};

const TabsRoot = forwardRef<ComponentRef<typeof TabsPrimitive.Root>, TabsRootProps>(
  function TabsRoot({ className, variant = 'default', ...props }, ref) {
    return (
      <TabsPrimitive.Root
        ref={ref}
        data-slot="tabs-root"
        data-variant={variant}
        className={clsx(styles.root, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const TabsRootProvider = forwardRef<
  ComponentRef<typeof TabsPrimitive.RootProvider>,
  TabsRootProviderProps
>(function TabsRootProvider({ className, variant = 'default', ...props }, ref) {
  return (
    <TabsPrimitive.RootProvider
      ref={ref}
      data-slot="tabs-root-provider"
      data-variant={variant}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const TabsList = forwardRef<
  ComponentRef<typeof TabsPrimitive.List>,
  ComponentProps<typeof TabsPrimitive.List>
>(function TabsList({ className, ...props }, ref) {
  return (
    <TabsPrimitive.List
      ref={ref}
      data-slot="tabs-list"
      className={clsx(styles.list, normalizeClassName(className))}
      {...props}
    />
  );
});

const TabsTrigger = forwardRef<
  ComponentRef<typeof TabsPrimitive.Trigger>,
  ComponentProps<typeof TabsPrimitive.Trigger>
>(function TabsTrigger({ className, ...props }, ref) {
  return (
    <TabsPrimitive.Trigger
      ref={ref}
      data-slot="tabs-trigger"
      className={clsx(styles.trigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const TabsIndicator = forwardRef<
  ComponentRef<typeof TabsPrimitive.Indicator>,
  ComponentProps<typeof TabsPrimitive.Indicator>
>(function TabsIndicator({ className, ...props }, ref) {
  return (
    <TabsPrimitive.Indicator
      ref={ref}
      data-slot="tabs-indicator"
      className={clsx(styles.indicator, normalizeClassName(className))}
      {...props}
    />
  );
});

const TabsContent = forwardRef<
  ComponentRef<typeof TabsPrimitive.Content>,
  ComponentProps<typeof TabsPrimitive.Content>
>(function TabsContent({ className, ...props }, ref) {
  return (
    <TabsPrimitive.Content
      ref={ref}
      data-slot="tabs-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const TabsContext = TabsPrimitive.Context;

const Tabs = Object.assign(TabsRoot, {
  Root: TabsRoot,
  RootProvider: TabsRootProvider,
  List: TabsList,
  Trigger: TabsTrigger,
  Indicator: TabsIndicator,
  Content: TabsContent,
  Context: TabsContext,
});

export { Tabs, useTabs, useTabsContext };
export type { TabsRootProps, TabsRootProviderProps, TabsVariant };
export type {
  TabsFocusChangeDetails,
  TabsValueChangeDetails,
  TabListProps as TabsListProps,
  TabTriggerProps as TabsTriggerProps,
  TabIndicatorProps as TabsIndicatorProps,
  TabContentProps as TabsContentProps,
  UseTabsContext,
  UseTabsProps,
  UseTabsReturn,
} from '@ark-ui/react/tabs';

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: flex;
    min-width: 0;
    flex-direction: column;
    gap: var(--tabs-gap, 0.75rem);
    color: var(--tabs-color, var(--color-foreground));

    &[data-orientation='vertical'] {
      flex-direction: row;
      align-items: stretch;
    }
  }

  .list {
    box-sizing: border-box;
    position: relative;
    z-index: 0;
    display: inline-flex;
    width: fit-content;
    max-width: 100%;
    align-items: stretch;
    gap: var(--tabs-list-gap, 0.25rem);
    padding: var(--tabs-list-padding-y, var(--tabs-list-padding, 0.25rem))
      var(--tabs-list-padding-x, var(--tabs-list-padding, 0.25rem));
    border: var(--tabs-list-border-width, var(--border-width-sm)) solid
      var(--tabs-list-border-color, var(--color-border));
    border-radius: var(--tabs-radius, var(--radius-lg));
    background-color: var(--tabs-list-bg, var(--color-muted));

    &[data-orientation='vertical'] {
      width: var(--tabs-vertical-list-width, 12rem);
      min-width: var(--tabs-vertical-list-width, 12rem);
      flex-direction: column;
    }

    .root[data-variant='line'] & {
      width: 100%;
      border-width: 0 0 var(--tabs-list-border-width, var(--border-width-sm));
      border-radius: 0;
      padding-inline: 0;
      background-color: transparent;
    }

    .root[data-orientation='vertical'][data-variant='line'] & {
      width: var(--tabs-vertical-list-width, 12rem);
      border-width: 0 var(--tabs-list-border-width, var(--border-width-sm)) 0 0;
    }
  }

  .trigger {
    box-sizing: border-box;
    position: relative;
    z-index: 1;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--tabs-tab-content-gap, 0.5rem);
    height: var(--tabs-tab-height, 2rem);
    margin: 0;
    appearance: none;
    border: 0;
    border-radius: var(--tabs-tab-radius, var(--radius-md));
    padding-inline: var(--tabs-tab-padding-x, 0.625rem);
    background: none;
    color: var(--tabs-tab-color, var(--color-muted-foreground));
    font: inherit;
    font-size: var(--tabs-tab-font-size, var(--text-sm));
    font-weight: var(--tabs-tab-font-weight, var(--weight-medium));
    line-height: var(--tabs-tab-line-height, var(--line-height-text-sm));
    text-decoration: none;
    user-select: none;
    white-space: nowrap;
    outline: 0;
    cursor: pointer;
    transition:
      color var(--tabs-tab-transition, var(--transition-default)),
      opacity var(--tabs-tab-transition, var(--transition-default));

    &[data-selected] {
      color: var(--tabs-tab-color-active, var(--color-foreground));
    }

    @media (hover: hover) {
      &:hover {
        color: var(--tabs-tab-color-hover, var(--tabs-tab-color-active, var(--color-foreground)));
      }
    }

    &:focus-visible {
      &::before {
        content: '';
        position: absolute;
        inset: 0;
        border-radius: inherit;
        outline: var(--tabs-focus-ring-width, var(--border-width-sm)) solid
          var(--tabs-focus-ring-color, var(--color-ring));
        outline-offset: var(--tabs-focus-ring-offset, 0);
      }
    }

    &[disabled],
    &[data-disabled] {
      cursor: default;
      opacity: var(--tabs-tab-disabled-opacity, var(--opacity-disabled));
      pointer-events: none;
    }

    & > svg {
      width: var(--tabs-tab-icon-size, 1rem);
      height: var(--tabs-tab-icon-size, 1rem);
      color: var(--tabs-tab-icon-color, currentColor);
      flex-shrink: 0;
    }
  }

  .indicator {
    position: absolute;
    z-index: 0;
    top: 50%;
    width: var(--width, 0);
    height: var(--tabs-indicator-size, 2rem);
    border-radius: var(--tabs-indicator-radius, var(--radius-md));
    background-color: var(--tabs-indicator-bg, var(--color-background));
    box-shadow: var(--tabs-indicator-shadow, var(--shadow-sm));
    translate: 0 -50%;
    transition:
      width var(--tabs-indicator-transition, var(--transition-default)),
      height var(--tabs-indicator-transition, var(--transition-default)),
      top var(--tabs-indicator-transition, var(--transition-default)),
      left var(--tabs-indicator-transition, var(--transition-default));

    .root[data-variant='line'] & {
      top: auto;
      bottom: 0;
      height: var(--tabs-line-indicator-size, 2px);
      border-radius: var(--tabs-line-indicator-radius, var(--radius-full));
      background-color: var(
        --tabs-line-indicator-bg,
        var(--tabs-tab-color-active, var(--color-foreground))
      );
      translate: none;
      box-shadow: none;
      transition:
        width var(--tabs-line-indicator-transition, var(--transition-default)),
        height var(--tabs-line-indicator-transition, var(--transition-default)),
        top var(--tabs-line-indicator-transition, var(--transition-default)),
        left var(--tabs-line-indicator-transition, var(--transition-default));
    }

    &[data-orientation='vertical'] {
      left: 50%;
      width: calc(100% - (var(--tabs-list-padding-x, var(--tabs-list-padding, 0.25rem)) * 2));
      height: var(--height, 0);
      translate: -50% 0;

      .root[data-variant='line'] & {
        bottom: auto;
        left: 0;
        width: var(--tabs-line-indicator-size, 2px);
        translate: none;
      }
    }
  }

  .content {
    box-sizing: border-box;
    flex: 1;
    min-width: 0;
    margin: 0;
    border: var(--tabs-border-width, var(--border-width-sm)) solid
      var(--tabs-border-color, var(--color-border));
    border-radius: var(--tabs-radius, var(--radius-lg));
    background-color: var(--tabs-bg, var(--color-background));
    padding: var(--tabs-panel-padding, 1rem);
    color: var(--tabs-panel-color, var(--tabs-color, var(--color-foreground)));
    font-size: var(--tabs-panel-font-size, var(--text-sm));
    line-height: var(--tabs-panel-line-height, var(--line-height-text-sm));
    outline: 0;

    &:focus-visible {
      outline: var(--tabs-focus-ring-width, var(--border-width-sm)) solid
        var(--tabs-focus-ring-color, var(--color-ring));
      outline-offset: var(--tabs-panel-focus-ring-offset, -1px);
      border-radius: inherit;
    }

    &[hidden]:not([hidden='until-found']) {
      display: none;
    }
  }
}

export { Tabs, useTabs, useTabsContext } from './Tabs';
export type { TabsRootProps, TabsRootProviderProps, TabsVariant } from './Tabs';
export type {
  TabContentProps as TabsContentProps,
  TabIndicatorProps as TabsIndicatorProps,
  TabListProps as TabsListProps,
  TabTriggerProps as TabsTriggerProps,
  TabsFocusChangeDetails,
  TabsValueChangeDetails,
  UseTabsContext,
  UseTabsProps,
  UseTabsReturn,
} from '@ark-ui/react/tabs';
